import sys

def digit_sum(n):
    return n if n < 10 else n // 10 + n % 10

def is_valid_luhn(card_number):
    # Remove spaces and get just the digits
    digits = card_number.replace(" ", "")

    if len(digits) != 16:
        return False

    total = 0
    for i, char in enumerate(digits):
        d = int(char)
        if i % 2 == 0:  # X positions (0, 2, 4, ...) - double these
            total += digit_sum(d * 2)
        else:  # y positions (1, 3, 5, ...) - add as is
            total += d

    return total % 10 == 0

def main():
    for line in sys.stdin:
        line = line.strip()
        if line and is_valid_luhn(line):
            print(line)

if __name__ == "__main__":
    main()

