def solve_n_queens(n):
    solutions = []

    def is_safe(board, row, col):
        # Check if a queen can be placed at board[row][col]
        # Check this row on left side
        for i in range(col):
            if board[i] == row:
                return False

        # Check upper diagonal on left side
        for i, j in zip(range(col-1, -1, -1), range(row-1, -1, -1)):
            if board[i] == j:
                return False

        # Check lower diagonal on left side
        for i, j in zip(range(col-1, -1, -1), range(row+1, n)):
            if board[i] == j:
                return False

        return True

    def solve(board, col):
        if col == n:
            # Convert to 1-indexed string representation
            solution = ''.join(str(board[i] + 1) for i in range(n))
            solutions.append(solution)
            return

        for row in range(n):
            if is_safe(board, row, col):
                board[col] = row
                solve(board, col + 1)
                board[col] = -1

    board = [-1] * n
    solve(board, 0)
    return solutions

# Print solutions for boards of sizes 4-8
