import sys
from functools import lru_cache

def parse(s, i):
    if i >= len(s):
        return None, i
    if s[i] == '0':
        if i + 1 >= len(s):
            return None, i
        if s[i + 1] == '0':
            # Lambda
            body, ni = parse(s, i + 2)
            return ('lam', body), ni
        else:
            # Application
            func, ni = parse(s, i + 2)
            arg, ni = parse(s, ni)
            return ('app', func, arg), ni
    else:
        # Variable: count 1s
        count = 0
        while i < len(s) and s[i] == '1':
            count += 1
            i += 1
        # Skip the trailing 0
        if i < len(s) and s[i] == '0':
            i += 1
        return ('var', count), i

def shift(term, d, c):
    if term[0] == 'var':
        if term[1] > c:
            return ('var', term[1] + d)
        else:
            return term
    elif term[0] == 'lam':
        return ('lam', shift(term[1], d, c + 1))
    elif term[0] == 'app':
        return ('app', shift(term[1], d, c), shift(term[2], d, c))

def subst(term, j, s):
    if term[0] == 'var':
        if term[1] == j:
            return s
        else:
            return term
    elif term[0] == 'lam':
        return ('lam', subst(term[1], j + 1, shift(s, 1, 0)))
    elif term[0] == 'app':
        return ('app', subst(term[1], j, s), subst(term[2], j, s))

def beta_reduce(body, arg):
    # Substitute arg for variable 1 in body, then shift down
    substituted = subst(body, 1, shift(arg, 1, 0))
    return shift(substituted, -1, 0)

def normalize(term):
    while True:
        new_term = step(term)
        if new_term is None:
            return term
        term = new_term

def step(term):
    if term[0] == 'var':
        return None
    elif term[0] == 'lam':
        new_body = step(term[1])
        if new_body is not None:
            return ('lam', new_body)
        return None
    elif term[0] == 'app':
        func, arg = term[1], term[2]
        # Try to reduce the application if func is a lambda
        if func[0] == 'lam':
            return beta_reduce(func[1], arg)
        # Try to reduce func
        new_func = step(func)
        if new_func is not None:
            return ('app', new_func, arg)
        # Try to reduce arg
        new_arg = step(arg)
        if new_arg is not None:
            return ('app', func, new_arg)
        return None

def to_binary(term):
    if term[0] == 'var':
        return '1' * term[1] + '0'
    elif term[0] == 'lam':
        return '00' + to_binary(term[1])
    elif term[0] == 'app':
        return '01' + to_binary(term[1]) + to_binary(term[2])

def solve(s):
    term, _ = parse(s, 0)
    normal = normalize(term)
    return to_binary(normal)

def main():
    input_data = sys.stdin.read().strip().split('\n')
    for line in input_data:
        line = line.strip()
        if line:
            print(solve(line))

if __name__ == "__main__":
    main()

